import{_ as t,o as e,c as r,ag as l}from"./chunks/framework.CNG7EpJN.js";const b=JSON.parse('{"title":"テーブル・フロアマップ","description":"","frontmatter":{"title":"テーブル・フロアマップ"},"headers":[],"relativePath":"tenant/05-tables.md","filePath":"tenant/05-tables.md"}'),d={name:"tenant/05-tables.md"};function o(i,a,n,h,s,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="_5-テーブル・フロアマップ" tabindex="-1">5. テーブル・フロアマップ <a class="header-anchor" href="#_5-テーブル・フロアマップ" aria-label="Permalink to &quot;5. テーブル・フロアマップ&quot;">​</a></h1><p>テーブル管理では、店舗の客席、QRコード、フロアマップ、着席状態を管理します。セルフオーダーを始める前に必ず設定してください。</p><h2 id="テーブル登録" tabindex="-1">テーブル登録 <a class="header-anchor" href="#テーブル登録" aria-label="Permalink to &quot;テーブル登録&quot;">​</a></h2><ol><li>管理画面でテーブル管理を開きます。</li><li>テーブル名、座席数、表示順を入力します。</li><li>保存後、必要に応じてQRコードを発行します。</li><li>テーブル番号と実際の席が一致しているか確認します。</li></ol><h2 id="qrコードの掲示" tabindex="-1">QRコードの掲示 <a class="header-anchor" href="#qrコードの掲示" aria-label="Permalink to &quot;QRコードの掲示&quot;">​</a></h2><p>発行したQRコードを印刷し、該当テーブルに掲示します。お客様が読み取ると、そのテーブルのセルフオーダー画面が開きます。</p><h2 id="フロアマップ" tabindex="-1">フロアマップ <a class="header-anchor" href="#フロアマップ" aria-label="Permalink to &quot;フロアマップ&quot;">​</a></h2><p>フロアマップでは、実際の席配置に近い形でテーブルを配置できます。スタッフが空席、着席、会計待ちなどの状況を把握しやすくなります。</p><h2 id="テーブルの開放と終了" tabindex="-1">テーブルの開放と終了 <a class="header-anchor" href="#テーブルの開放と終了" aria-label="Permalink to &quot;テーブルの開放と終了&quot;">​</a></h2><p>営業中は、お客様が着席したタイミングでテーブルを開放します。退店後は会計完了と片付けを確認し、次のお客様に使える状態にしてください。</p><h2 id="相席・分割利用" tabindex="-1">相席・分割利用 <a class="header-anchor" href="#相席・分割利用" aria-label="Permalink to &quot;相席・分割利用&quot;">​</a></h2><p>同じテーブルを複数グループで使う運用や、注文を分けたい場合は、店舗の運用ルールに合わせて管理してください。迷う場合はPOSLAサポートへご相談ください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>QRコードを読み取れない</td><td>印刷のかすれ、掲示位置、カメラの距離を確認してください。</td></tr><tr><td>違うテーブルが開く</td><td>QRコードを再発行し、貼り間違いがないか確認してください。</td></tr><tr><td>フロアマップが実席と合わない</td><td>テーブル位置をドラッグして調整してください。</td></tr><tr><td>注文が別テーブルに入る</td><td>テーブル番号とQRコードの対応を確認してください。</td></tr></tbody></table>',14)])])}const p=t(d,[["render",o]]);export{b as __pageData,p as default};
